#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build the graph: original edges and reversed edges (for possible switches)
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    unordered_map<long long, vector<pair<long long, long long>>> reversed_edges; // To store incoming edges for each node

    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];
        graph[u].emplace_back(v, w);
        reversed_edges[v].emplace_back(u, w);
    }

    // Dijkstra's algorithm with state (node, whether the switch has been used)
    // dist[node][0] = min cost to reach node without using switch
    // dist[node][1] = min cost to reach node after using switch somewhere
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;

    // Priority queue: (total_cost, node, switch_used)
    priority_queue<tuple<long long, long long, bool>, 
                   vector<tuple<long long, long long, bool>>, 
                   greater<tuple<long long, long long, bool>>> pq;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used] = pq.top();
        pq.pop();

        if (u == n - 1) {
            return current_dist;
        }

        if (current_dist > dist[u][used]) {
            continue;
        }

        // Explore normal edges
        for (const auto& [v, w] : graph[u]) {
            if (current_dist + w < dist[v][used]) {
                dist[v][used] = current_dist + w;
                pq.emplace(dist[v][used], v, used);
            }
        }

        // If switch hasn't been used yet, try using it at current node
        if (!used) {
            for (const auto& [v, w] : reversed_edges[u]) {
                long long new_cost = current_dist + 2 * w;
                if (new_cost < dist[v][true]) {
                    dist[v][true] = new_cost;
                    pq.emplace(new_cost, v, true);
                }
            }
        }
    }

    long long result = min(dist[n - 1][0], dist[n - 1][1]);
    return result == LLONG_MAX ? -1 : result;
}
